    goal = (frozenset(), frozenset(['A','B']))

    queue = deque([(start, 0)])  
    visited = {start}

    max_steps = 20
    while queue:
        (left, right, boat), steps = queue.popleft()

        if (left, right) == goal:
            return steps

        if steps >= max_steps:
            continue

        if boat == 0:
            current_side = left
            other_side = right
            next_boat = 1
