# P5: 3 missionaries (M) and 3 cannibals (C). Boat capacity = 2. 
# Must always carry at least 1. On any bank, if missionaries present, cannibals <= missionaries.

def is_valid_p5(left_m, left_c, right_m, right_c):
    # Check left bank
    if left_m > 0 and left_c > left_m:
        return False
    # Check right bank  
    if right_m > 0 and right_c > right_m:
        return False
    return True

from collections import deque

def solve_p5():
    start = (3, 3, 0)  # (left_m, left_c, boat_side) - boat 0=left, 1=right
    goal = (0, 0, 0)  # all on right, don't care about boat

    queue = deque([(start, 0)])
    visited = {start}

    while queue:
        (lm, lc, boat), steps = queue.popleft()
        rm, rc = 3 - lm, 3 - lc

        if (lm, lc) == (0, 0):
            return steps

        if not is_valid_p5(lm, lc, rm, rc):
            continue

        # Boat capacity is 2, must have at least 1
        if boat == 0:  # boat on left
            # Can take 1-2 people from left to right
            for num in range(1, 3):
                from itertools import combinations
                # Generate all combinations of M and C from left
                for m in range(min(num, lm) + 1):
                    c = num - m
                    if c <= lc:
                        new_lm, new_lc = lm - m, lc - c
                        new_rm, new_rc = rm + m, rc + c
                        new_state = (new_lm, new_lc, 1)
                        if new_state not in visited and is_valid_p5(new_lm, new_lc, new_rm, new_rc):
                            visited.add(new_state)
                            queue.append((new_state, steps+1))
        else:  # boat on right
            for num in range(1, 3):
                for m in range(min(num, rm) + 1):
                    c = num - m
                    if c <= rc:
                        new_lm, new_lc = lm + m, lc + c
                        new_rm, new_rc = rm - m, rc - c
                        new_state = (new_lm, new_lc, 0)
                        if new_state not in visited and is_valid_p5(new_lm, new_lc, new_rm, new_rc):
                            visited.add(new_state)
                            queue.append((new_state, steps+1))

    return "IMPOSSIBLE"

print(f"P5: {solve_p5()}")
