# Let me re-verify by looking at the solution path for P3 (4 people, capacity 2)

from collections import deque

def solve_p3_with_path():
    people = ['A','B','C','D']
    start = (frozenset(people), frozenset(), 0)
    goal = (frozenset(), frozenset(people))

    queue = deque([(start, 0, [])])
    visited = {start}

    while queue:
        (left, right, boat), steps, path = queue.popleft()

        if (left, right) == goal:
            return steps, path

        if boat == 0:
            for num in range(1, min(2, len(left))+1):
                from itertools import combinations
                for group in combinations(left, num):
                    new_left = left - set(group)
                    new_right = right | set(group)
                    new_state = (new_left, new_right, 1)
                    if new_state not in visited:
                        visited.add(new_state)
                        queue.append((new_state, steps+1, path + [f"{group}->R"]))
        else:
            for num in range(1, min(2, len(right))+1):
                from itertools import combinations
                for group in combinations(right, num):
                    new_left = left | set(group)
                    new_right = right - set(group)
                    new_state = (new_left, new_right, 0)
                    if new_state not in visited:
                        visited.add(new_state)
                        queue.append((new_state, steps+1, path + [f"{group}->L"]))

    return "IMPOSSIBLE", []

steps, path = solve_p3_with_path()
print(f"P3: {steps}")
print(f"Path: {path[:10]}")  # show first 10
